Semantic Kernel is Microsoft's open-source SDK for building AI-powered apps. It orchestrates LLM calls, plugins, memory, and agents.

```csharp
// Install: dotnet add package Microsoft.SemanticKernel

var kernel = Kernel.CreateBuilder()
    .AddAzureOpenAIChatCompletion(
        deploymentName: "gpt-4o",
        endpoint: configuration["AzureOpenAI:Endpoint"]!,
        credentials: new DefaultAzureCredential())
    .Build();

// 1. Simple prompt
var result = await kernel.InvokePromptAsync(
    "Explain {{$topic}} in one paragraph for a junior developer.",
    new KernelArguments { ["topic"] = "dependency injection" });
Console.WriteLine(result);

// 2. Native function plugin (your C# code as a tool the LLM can call)
public class OrderPlugin
{
    [KernelFunction, Description("Get order status by order ID")]
    public async Task<string> GetOrderStatusAsync(int orderId, AppDbContext db)
    {
