The Repository pattern abstracts data access behind an interface, making your business logic independent of EF Core or any specific data store.

```csharp
// Generic repository interface
public interface IRepository<T> where T : class
{
    Task<T?> GetByIdAsync(int id);
    Task<IEnumerable<T>> GetAllAsync();
    Task AddAsync(T entity);
    Task UpdateAsync(T entity);
    Task DeleteAsync(int id);
}

// EF Core implementation
public class ProductRepository : IRepository<Product>
{
    private readonly AppDbContext _db;
    public ProductRepository(AppDbContext db) => _db = db;

    public Task<Product?> GetByIdAsync(int id) =>
        _db.Products.FindAsync(id).AsTask();

    public async Task<IEnumerable<Product>> GetAllAsync() =>
        await _db.Products.AsNoTracking().ToListAsync();

    public async Task AddAsync(Product entity)
    {
        await _db.Products.AddAsync(entity);
        await _db.SaveChangesAsync();
    }

    public async Task UpdateAsync(Product entity)
    {
        _db.Products.Update(entity);
        await _db.SaveChangesAsync();
    }

    public async Task DeleteAsync(int id)
    {
        var entity = await _db.Products.FindAsync(id);
        if (entity is not null)
        {
            _db.Products.Remove(entity);
            await _db.SaveChangesAsync();
        }
    }
}

// Registration
builder.Services.AddScoped<IRepository<Product>, ProductRepository>();
```

Pair with the **Unit of Work** pattern when you need multiple repositories to share a single transaction and `SaveChangesAsync` call.

