The options pattern binds configuration sections to strongly typed C# classes, replacing magic strings with type-safe objects.

```json
// appsettings.json
{
  "Email": {
    "SmtpHost": "smtp.sendgrid.net",
    "SmtpPort": 587,
    "FromAddress": "noreply@myapp.com"
  }
}
```

```csharp
// Options class
public class EmailOptions
{
    public const string Section = "Email";

    [Required] public string SmtpHost { get; set; } = string.Empty;
    [Range(1, 65535)] public int SmtpPort { get; set; }
    [Required, EmailAddress] public string FromAddress { get; set; } = string.Empty;
}

// Register in Program.cs
builder.Services.AddOptions<EmailOptions>()
    .BindConfiguration(EmailOptions.Section)
    .ValidateDataAnnotations()     // throws on startup if config is invalid
    .ValidateOnStart();

// Inject and use
public class EmailService
{
    private readonly EmailOptions _options;
    public EmailService(IOptions<EmailOptions> options) => _options = options.Value;

    public void Send(string to, string subject)
    {
        Console.WriteLine($"Sending from {_options.FromAddress} via {_options.SmtpHost}:{_options.SmtpPort}");
    }
}
```

Use `IOptions<T>` for singleton/startup config, `IOptionsSnapshot<T>` for per-request (reads updated config per request), `IOptionsMonitor<T>` for change notifications at runtime.
